example.code:
class ArticleDraft(BaseModel):
    schema_version: Literal["v3"] = "v3"
    body: str
    title: str
    tags: list[str]

PARSERS: dict[str, type[BaseModel]] = {
    "v2": ArticleDraftV2,
    "v3": ArticleDraft,
}

def parse_event(payload: dict) -> BaseModel:
    cls = PARSERS.get(payload["schema_version"])
    if cls is None:
        raise UnknownSchemaVersion(payload["schema_version"])
    return cls.model_validate(payload)
